import java.util.*;

public class Department {
    private int id;
    private String name;
    private List<Employee> employees = new ArrayList<>();

    public Department(int id, String name) {
        this.id = id; this.name = name;
    }

    public void addEmployee(Employee e) {
        employees.add(e);
        e.setDepartment(this);
    }

    public int getId() { return id; }
    public String getName() { return name; }
    public List<Employee> getEmployees() { return Collections.unmodifiableList(employees); }

    @Override
    public String toString() { return "Department{" + id + ", " + name + "}"; }
}

public class Employee {
    private int id;
    private String name;
    private Department department; // Many-to-One side

    public Employee(int id, String name) {
        this.id = id; this.name = name;
    }

    // TODO: setDepartment(), getDepartment(), getId(), getName()

    @Override
    public String toString() { return "Employee{" + id + ", " + name + "}"; }
}

public class Main {
    public static void main(String[] args) {
        Department eng = new Department(1, "Engineering");
        Department mkt = new Department(2, "Marketing");

        eng.addEmployee(new Employee(1, "Alice"));
        eng.addEmployee(new Employee(2, "Bob"));
        mkt.addEmployee(new Employee(3, "Carol"));

        // Print from department side
        System.out.println(eng.getName() + " employees:");
        eng.getEmployees().forEach(e -> System.out.println("  " + e.getName()));

        // Print from employee side (inverse navigation)
        Employee emp = eng.getEmployees().get(0);
        System.out.println(emp.getName() + " works in: " + emp.getDepartment().getName());

        System.out.println("Engineering employee count: " + eng.getEmployees().size());
    }
}

import java.util.*;

public class LazyList<T> extends AbstractList<T> {
    private List<T> data;
    private boolean loaded = false;
    private String entityName;

    public LazyList(String entityName) {
        this.entityName = entityName;
    }

    private void loadIfNeeded() {
        if (!loaded) {
            System.out.println("[LAZY] Loading " + entityName + " collection from database...");
            // Simulate loading
            data = new ArrayList<>();
            loaded = true;
        }
    }

    public void initData(T... items) {
        if (data == null) data = new ArrayList<>();
        data.addAll(Arrays.asList(items));
        loaded = true;
    }

    @Override public T get(int index) { loadIfNeeded(); return data.get(index); }
    @Override public int size() { loadIfNeeded(); return data.size(); }
}

public class AuthorEager {
    private String name;
    private List<String> books; // EAGER: loaded immediately

    public AuthorEager(String name, List<String> books) {
        System.out.println("[EAGER] Loading author '" + name + "' AND all books immediately");
        this.name = name;
        this.books = books;
    }
    public String getName() { return name; }
    public List<String> getBooks() { return books; }
}

public class AuthorLazy {
    private String name;
    private LazyList<String> books; // LAZY: loaded on access

    public AuthorLazy(String name) {
        System.out.println("[LAZY] Loading author '" + name + "' only");
        this.name = name;
        this.books = new LazyList<>("books for " + name);
    }

    public void setBooks(String... bookList) { books.initData(bookList); }
    public String getName() { return name; }
    public LazyList<String> getBooks() { return books; }
}

public class Main {
    public static void main(String[] args) {
        System.out.println("--- EAGER Loading ---");
        AuthorEager eager = new AuthorEager("Joshua Bloch",
            Arrays.asList("Effective Java", "Java Puzzlers"));
        System.out.println("Author created. Accessing books: " + eager.getBooks());

        System.out.println("\n--- LAZY Loading ---");
        AuthorLazy lazy = new AuthorLazy("Martin Fowler");
        lazy.setBooks("Refactoring", "Patterns of Enterprise Application Architecture");
        System.out.println("Author created. Not accessed books yet.");
        System.out.println("Now accessing: " + lazy.getBooks().size() + " books");
    }
}
